const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const f = body.filters || {};
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 100, 1), 500);
const sinceIso = f.since || null; // ISO-8601; optional

// Build a PostgREST query string for each source table. Filters that
// don't apply to a given table (e.g. client_id on email_log) are
// silently dropped — that's reconciled in Shape Response.
function qsBase(orderCol) {
  const parts = ['order=' + orderCol + '.desc', 'limit=' + limit];
  if (sinceIso) parts.push(orderCol + '=gte.' + encodeURIComponent(sinceIso));
  return parts;
}

// messages_sent: sms / whatsapp / voice / video_link / email writer target.
// Columns: id,lead_id,client_id,channel,direction,content,status,external_id,
//          sent_at,delivered_at,read_at,replied_at,error_message,cost_cents.
const qsMessages = ['select=id,lead_id,client_id,channel,direction,content,status,external_id,sent_at,delivered_at,read_at,replied_at,error_message,cost_cents']
  .concat(qsBase('sent_at'));
if (f.client_id) qsMessages.push('client_id=eq.' + encodeURIComponent(f.client_id));
if (f.lead_id)   qsMessages.push('lead_id=eq.'   + encodeURIComponent(f.lead_id));
if (f.channel && f.channel !== 'all') qsMessages.push('channel=eq.' + encodeURIComponent(f.channel));

// outreach_log: cross-channel state log (linkedin / whatsapp campaign / video-ready / voice).
// Columns: id,lead_id,client_id,channel,channel_status,subject,message_excerpt,sent_at,metadata.
const qsOutreach = ['select=id,lead_id,client_id,channel,channel_status,subject,message_excerpt,sent_at,metadata']
  .concat(qsBase('sent_at'));
if (f.client_id) qsOutreach.push('client_id=eq.' + encodeURIComponent(f.client_id));
if (f.lead_id)   qsOutreach.push('lead_id=eq.'   + encodeURIComponent(f.lead_id));
if (f.channel && f.channel !== 'all') qsOutreach.push('channel=eq.' + encodeURIComponent(f.channel));

// email_log: Postmark email writer target. No lead_id / client_id columns.
// Columns: id,template_alias,to_email,postmark_message_id,postmark_error_code,sent_at.
// Skipped when client_id/lead_id filter set unless caller explicitly
// wants the email channel; otherwise it would just return noise.
const skipEmailLog = (f.client_id || f.lead_id) && f.channel !== 'email' && f.channel !== 'all' && f.channel;
const qsEmail = ['select=id,template_alias,to_email,postmark_message_id,postmark_error_code,sent_at']
  .concat(qsBase('sent_at'));

return { json: {
  token: token,
  qs_messages: qsMessages.join('&'),
  qs_outreach: qsOutreach.join('&'),
  qs_email:    qsEmail.join('&'),
  skip_email:  !!skipEmailLog,
  filters:     f,
  limit:       limit
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const inputs = $('Extract Inputs').item.json;
return { json: { ok: true, qs_messages: inputs.qs_messages, qs_outreach: inputs.qs_outreach, qs_email: inputs.qs_email, skip_email: inputs.skip_email, filters: inputs.filters, limit: inputs.limit } };

// Canonical allOf() — collapses n8n's array-split + auto-unwrap on
// multi-row PostgREST responses back to a single array.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    // Single-row auto-unwrap: object with table columns -> wrap in array.
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0])) {
      const o = items[0];
      if (o.id || o.sent_at) return [o];
    }
    return items.filter(function (x) { return x && (x.id || x.sent_at); });
  } catch (e) { return []; }
};

const inputs   = $('Extract Inputs').item.json;
const filters  = inputs.filters || {};
const limit    = inputs.limit || 100;

const messages = allOf('Query messages_sent');
const outreach = allOf('Query outreach_log');
const emails   = inputs.skip_email ? [] : allOf('Query email_log');

// Normalize all three sources to a unified shape so the frontend
// renders one table without per-source branching.
function excerpt(s, n) {
  if (!s) return '';
  s = String(s);
  if (s.length <= n) return s;
  return s.slice(0, n).trim() + '…';
}

const normMsg = function (r) {
  return {
    source:          'messages_sent',
    id:              r.id,
    channel:         r.channel || 'unknown',
    direction:       r.direction || 'outbound',
    subject:         null,
    content:         r.content || '',
    content_excerpt: excerpt(r.content, 140),
    lead_id:         r.lead_id || null,
    client_id:       r.client_id || null,
    recipient:       null,
    status:          r.status || 'unknown',
    sent_at:         r.sent_at,
    delivered_at:    r.delivered_at || null,
    read_at:         r.read_at || null,
    replied_at:      r.replied_at || null,
    error_message:   r.error_message || null,
    cost_cents:      typeof r.cost_cents === 'number' ? r.cost_cents : null,
    external_id:     r.external_id || null
  };
};

const normOut = function (r) {
  return {
    source:          'outreach_log',
    id:              r.id,
    channel:         r.channel || 'unknown',
    direction:       'outbound',
    subject:         r.subject || null,
    content:         r.message_excerpt || '',
    content_excerpt: excerpt(r.message_excerpt, 140),
    lead_id:         r.lead_id || null,
    client_id:       r.client_id || null,
    recipient:       null,
    status:          r.channel_status || 'sent',
    sent_at:         r.sent_at,
    delivered_at:    null,
    read_at:         null,
    replied_at:      null,
    error_message:   null,
    cost_cents:      null,
    external_id:     null,
    metadata:        r.metadata || null
  };
};

const normEm = function (r) {
  const failed = !!r.postmark_error_code;
  return {
    source:          'email_log',
    id:              r.id,
    channel:         'email',
    direction:       'outbound',
    subject:         r.template_alias || null,
    content:         r.template_alias || '',
    content_excerpt: r.template_alias || '',
    lead_id:         null,
    client_id:       null,
    recipient:       r.to_email || null,
    status:          failed ? 'failed' : 'sent',
    sent_at:         r.sent_at,
    delivered_at:    null,
    read_at:         null,
    replied_at:      null,
    error_message:   r.postmark_error_code || null,
    cost_cents:      null,
    external_id:     r.postmark_message_id || null
  };
};

const all = [].concat(
  messages.map(normMsg),
  outreach.map(normOut),
  emails.map(normEm)
);

// Sort newest first; cap at the user-requested limit (each source was
// already capped at limit, so worst case here is 3*limit before slice).
all.sort(function (a, b) {
  const ta = a.sent_at ? new Date(a.sent_at).getTime() : 0;
  const tb = b.sent_at ? new Date(b.sent_at).getTime() : 0;
  return tb - ta;
});
const rows = all.slice(0, limit);

// Per-channel counts for the KPI strip on the frontend.
const byChannel = {};
for (const r of all) byChannel[r.channel] = (byChannel[r.channel] || 0) + 1;
const byStatus = {};
for (const r of all) byStatus[r.status] = (byStatus[r.status] || 0) + 1;

return { json: {
  ok: true,
  count_returned: rows.length,
  count_total:    all.length,
  by_channel:     byChannel,
  by_status:      byStatus,
  filters:        filters,
  note:           inputs.skip_email
                    ? 'email_log filtered out — no client_id/lead_id columns on that table'
                    : null,
  rows:           rows
} };
